function depositWithExpiry(
    address payable vault,
    address asset,
    uint256 amount,
    string memory memo,
    uint256 expiration
) external payable {
    require(block.timestamp < expiration, "THORChain_Router: expired");
    deposit(vault, asset, amount, memo);
}
